func main() {
    // Literal
    ages := map[string]int{"alice": 30, "bob": 25}
    fmt.Println(ages)  // map[alice:30 bob:25]

    // make()
    counts := make(map[string]int)
    counts["x"] = 1
    fmt.Println(counts)  // map[x:1]
    fmt.Println(len(ages))  // 2
}

