func main() {
    m := map[string]int{"a": 1, "b": 2}

    val, ok := m["a"]
    fmt.Println(val, ok)   // 1 true

    val, ok = m["z"]
    fmt.Println(val, ok)   // 0 false

    if v, ok := m["b"]; ok {
        fmt.Println("found:", v)  // found: 2
    }
}

