func main() {
    m := map[string]int{"a": 1, "b": 2, "c": 3}
    delete(m, "b")
    fmt.Println(m)  // map[a:1 c:3]

    for k, v := range m {
        fmt.Printf("%s -> %d\n", k, v)
    }
}

